/* Return the largest sum of any contiguous subarray in the vector x.
   This implementation uses Kadane's algorithm, which runs in O(n) time
   and preserves the exact behaviour of the original quadratic
   algorithm.
*/
int maximumSubarray(std::vector<int> const& x) {
    // Handle empty input – same semantics as the original code
    if (x.empty()) return std::numeric_limits<int>::lowest();

    int currentSum = 0;
    int bestSum    = std::numeric_limits<int>::lowest();

    for (int val : x) {
        if (currentSum < 0)
            currentSum = val;          // start a new subarray
        else
            currentSum += val;        // extend the current subarray

        if (currentSum > bestSum)
            bestSum = currentSum;
    }

    return bestSum;
}
