/*
   Compute the highest node degree in the undirected graph.
   The graph is defined in the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major order and is symmetric.
*/
int maxDegree(std::vector<int> const& A, size_t N) {
    // Access data through a raw pointer for faster indexing
    const int *data = A.data();

    int highest = 0;

    // Parallel reduction to compute the maximum degree
#pragma omp parallel for reduction(max:highest)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int deg = 0;

        // Sum the elements of row i
        for (int j = 0; j < static_cast<int>(N); ++j) {
            deg += data[i * static_cast<int>(N) + j];
        }

        if (deg > highest) highest = deg;
    }

    return highest;
}
