/// Compute for each i the minimum of x[0..i] in place.
/// For best performance on modern x86-64, we use a hand‑rolled loop
/// instead of std::inclusive_scan, which incurs abstracting overhead.
inline void partialMinimums(std::vector<float> &x) {
    if (x.empty()) return;
    const float max_val = std::numeric_limits<float>::max();

    // Start the running minimum at a value greater than any possible element.
    float current_min = max_val;
    auto *p = x.data();
    const auto *end = p + x.size();

    for (; p != end; ++p) {
        // The ternary is compiler‑friendly to predict the min branch.
        current_min = (p[0] < current_min) ? p[0] : current_min;
        p[0] = current_min;
    }
}
