/* In the vector x negate the odd values and divide the even values by 2.
   The implementation is OpenMP‑parallelised for 8 threads and avoids
   expensive modulo operations.
   Example:
   input : [16, 11, 12, 14, 1, 0, 5]
   output: [8, -11, 6, 7, -1, 0, -5]
*/
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();
    const std::size_t chunk = 1 << 10;          // 1024 elements per chunk
#pragma omp parallel for schedule(static, chunk) num_threads(8)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        int v = x[i];
        if ((v & 1) == 0)          // even
            x[i] = v >> 1;        // divide by 2 (same as /2 for signed ints)
        else
            x[i] = -v;             // negate odd
    }
}
