#include <omp.h>

/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
inline void pixelCounts(std::vector<int> const& image, std::array<std::size_t, 256> &bins) {
    // Clear output bins
    bins.fill(0);

    // If the image is empty, nothing to do
    if (image.empty()) return;

    // Per‑thread local bins to avoid contention
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 256>> localBins(nthreads);
    for (auto &b : localBins) b.fill(0);

    // Parallel loop
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto &local = localBins[tid];
        #pragma omp for
        for (std::size_t i = 0; i < image.size(); ++i) {
            local[static_cast<unsigned char>(image[i])]++;
        }
    }

    // Merge local bins into the output
    for (int t = 0; t < nthreads; ++t) {
        const auto &local = localBins[t];
        for (int v = 0; v < 256; ++v) {
            bins[v] += local[v];
        }
    }
}
