/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
inline bool reduceLogicalXOR(std::vector<bool> const& x) {
    // Perform the XOR reduction in parallel using OpenMP.
    // We accumulate into an unsigned long long, which is large enough
    // to hold the result of XORing any number of bools.
    unsigned long long acc = 0;

    #pragma omp parallel for reduction(^ : acc)
    for (std::size_t i = 0; i < x.size(); ++i) {
        acc ^= static_cast<unsigned long long>(x[i]);  // bool → ull for XOR
    }

    // Convert the accumulator back to bool
    return static_cast<bool>(acc);
}
