19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>
#include <cstdint>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A.  A is an NxN adjacency matrix stored in
   row-major order.  The graph is guaranteed to be connected. */
inline int shortestPathLength(const std::vector<int> &A, size_t N,
                              int source, int dest) {
    // Use a narrow byte per vertex for cache friendliness
    std::vector<uint8_t> visited(N, 0);

    // Simple circular queue implemented as a plain array.  The maximum
    // number of elements the queue will hold is N, so we allocate N+1
    // slots to distinguish full vs empty.
    std::vector<int> q(N + 1);
    size_t head = 0, tail = 0;

    auto enqueue = [&](int v, int d) {
        q[tail] = (v << 16) | (d & 0xFFFF);        // pack vertex and distance
        tail = (tail + 1) % q.size();
    };
    auto dequeue = [&]() {
        auto val = q[head];
        head = (head + 1) % q.size();
        int v = val >> 16;
        int d = val & 0xFFFF;
        return std::pair<int, int>{v, d};
    };

    visited[source] = 1;
    enqueue(source, 0);

    while (head != tail) {
        auto [curr, dist] = dequeue();
        if (curr == dest) return dist;

        size_t row_offset = curr * N;
        for (size_t i = 0; i < N; ++i) {
            if (A[row_offset + i] && !visited[i]) {
                visited[i] = 1;
                enqueue(static_cast<int>(i), dist + 1);
            }
        }
    }

    return std::numeric_limits<int>::max(); // unreachable (should not happen)
}
