55_transform_relu:
```cpp
#pragma once
#include <vector>
#include <immintrin.h>
#include <omp.h>
#include <algorithm>
#include <cstddef>

/*
 * Compute the ReLU function on every element of x. Elements less than zero become zero,
 * while elements greater than zero stay the same.
 * Example:
 * input:  [-1.8, 24.0, 1.2, 0.0, -5.1, -0.2, 4.5]
 * output: [0, 24.0, 1.2, 0, 0, 0, 4.5]
 */
static constexpr size_t AVX2_STRIDE = 4;   // 4 doubles per __m256d

inline void relu(std::vector<double> &x) {
    const size_t n = x.size();
    if (n == 0) return;

    const double zero = 0.0;
    const __m256d vmax = _mm256_set1_pd(zero);

    // Parallel SIMD processing
    #pragma omp parallel
    {
        // Each thread processes a contiguous chunk
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i + AVX2_STRIDE <= n; i += AVX2_STRIDE) {
            __m256d v = _mm256_loadu_pd(&x[i]);    // load 4 doubles
            v = _mm256_max_pd(vmax, v);            // element‑wise max with 0
            _mm256_storeu_pd(&x[i], v);            // store back
        }

        // Tail: handle any remaining elements (not divisible by 4)
        #pragma omp for schedule(static)
        for (std::size_t i = ((n + AVX2_STRIDE - 1) / AVX2_STRIDE) * AVX2_STRIDE; i < n; ++i) {
            x[i] = std::max(0.0, x[i]);
        }
    }
}
