#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output) {
    const std::size_t n = input.size();

    if (n == 0) return;

    // Avoid branching inside the parallel loop by handling boundaries explicitly
    // and processing the interior in parallel.
    const double inv3 = 1.0 / 3.0;

    // first element
    output[0] = (input[0] + input[1]) * inv3;

    // interior
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        output[i] = (input[i-1] + input[i] + input[i+1]) * inv3;
    }

    // last element
    if (n > 1) {
        output[n-1] = (input[n-2] + input[n-1]) * inv3;
    }
}
