#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

struct Point
{
    double x;
    double y;
};

/*
 * Count the number of cartesian points in each quadrant.
 * The vector `points` contains a list of `Point` objects.
 * Store the counts in `bins`.
 *
 * Implementation notes:
 * - Use OpenMP parallel for with a reduction to aggregate quadrant counts.
 * - Use a simple branchless classification to minimise branch mis‑predictions.
 * - The accuracy is preserved because every point is processed exactly once.
 */
inline void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4> &bins)
{
    // Ensure bins are zeroed before the parallel reduction.
    std::fill(bins.begin(), bins.end(), 0);

    // Local per-thread counters for the reduction.
    #pragma omp parallel
    {
        std::size_t local[4] = {0, 0, 0, 0};

        #pragma omp for nowait
        for (std::size_t i = 0; i < points.size(); ++i)
        {
            const Point& p = points[i];
            // Branchless decision:
            //  q0 = (p.x >= 0) & (p.y >= 0)
            //  q1 = (p.x <  0) & (p.y >= 0)
            //  q2 = (p.x <  0) & (p.y <  0)
            //  q3 = (p.x >= 0) & (p.y <  0)
            int q0 = static_cast<int>(p.x >= 0 && p.y >= 0);
            int q1 = static_cast<int>(p.x <  0 && p.y >= 0);
            int q2 = static_cast<int>(p.x <  0 && p.y <  0);
            int q3 = static_cast<int>(p.x >= 0 && p.y <  0);

            local[0] += q0;
            local[1] += q1;
            local[2] += q2;
            local[3] += q3;
        }

        // Merge local counters into the global result.
        #pragma omp atomic
