#pragma once
#include <vector>
#include <cstddef>

/* Find with path compression */
static inline int find_set(std::vector<int>& parent, int v) {
    while (parent[v] != v) {
        parent[v] = parent[parent[v]];
        v = parent[v];
    }
    return v;
}

/* Union by rank */
static inline void union_set(std::vector<int>& parent, std::vector<int>& rank, int a, int b) {
    int ra = find_set(parent, a);
    int rb = find_set(parent, b);
    if (ra == rb) return;
    if (rank[ra] < rank[rb]) {
        parent[ra] = rb;
    } else if (rank[ra] > rank[rb]) {
        parent[rb] = ra;
    } else {
        parent[rb] = ra;
        ++rank[ra];
    }
}

/*
 * Count the number of connected components in the undirected graph
 * represented by the adjacency matrix A (row‑major).
 * The implementation uses a Union‑Find (Disjoint Set Union) data
 * structure with path compression and union by rank, which
 * achieves near‑linear time for sparse graphs and excellent
 * cache locality for dense ones.
 */
int componentCount(std::vector<int> const& A, std::size_t N) {
    if (N == 0) return 0;

    std::vector<int> parent(N);
    std::vector<int> rank(N, 0);
    for (std::size_t i = 0; i < N; ++i) parent[i] = static_cast<int>(i);

    /* Only need to scan upper triangle to avoid duplicate work */
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t base = i * N;
        for (std::size_t j = i + 1; j < N; ++j) {
            if (A[base + j]) {
                union_set(parent, rank, static_cast<int>(i), static_cast<int>(j));
            }
        }
    }

    /* Count unique roots */
    int components = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (find_set(parent, static_cast<int>(i)) == static_cast<int>(i)) {
            ++components;
        }
    }
    return components;
}
