// Computes the inclusive prefix sum of `x` into `output`.
// This is a parallel implementation that preserves the exact
// behavior of the original sequential std::inclusive_scan.
inline void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output) {
    const std::size_t n = x.size();
    if (n == 0) return;

    output.resize(n);          // ensure output has the correct size

    // Choose a block size; 1K elements per thread is usually a good trade‑off.
    const std::size_t blockSize = 1024;
    const std::size_t numBlocks = (n + blockSize - 1) / blockSize;
    std::vector<int64_t> blockSums(numBlocks, 0);

    // 1. Parallel local scans and compute block sums
    #pragma omp parallel for schedule(static,1)
    for (std::size_t b = 0; b < numBlocks; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;        // local inclusive scan
        }
        blockSums[b] = sum;         // cumulative sum of this block
    }

    // 2. Compute prefix sums of block sums sequentially
    //     (this part is usually very fast because the number of blocks is small)
    int64_t acc = 0;
    for (std::size_t b = 0; b < numBlocks; ++b) {
        const int64_t curSum = blockSums[b];
        blockSums[b] = acc;         // new offset for this block
        acc += curSum;
    }

    // 3. Add the block offsets to each element in parallel
    #pragma omp parallel for schedule(static,1)
    for (std::size_t b = 0; b < numBlocks; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        const int64_t offset = blockSums[b];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
