struct COOElement {
    size_t row, column;
    double value;
};

/* Optimised sparse‑sparse matrix multiplication:
   Y = A × X
   A : M×K sparse (COO)
   X : K×N sparse (COO)
   Y : M×N dense (row‑major)

   The algorithm builds a row‑index for X to avoid scanning the
   entire X for each element in A. Parallel work is split over the
   elements of A; each thread writes to a private copy of Y and the
   results are summed at the end.  All operations preserve the
   original semantics.
*/
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    // initialise result matrix
    Y.assign(M * N, 0.0);

    /* Build a hash map from a row index of X to the elements in that row.
       This reduces the inner loop from O(|X|) to O(#elements in the row).   */
    std::unordered_map<size_t, std::vector<COOElement>> x_by_row;
    x_by_row.reserve(X.size());
    for (const auto& xe : X)
        x_by_row[xe.row].push_back(xe);

    // number of threads we will use
    int nthreads = omp_get_max_threads();
    // thread‑private copies of Y
    std::vector<std::vector<double>> tempY(nthreads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        size_t tid = omp_get_thread_num();
        const auto& ae = A[i];
        auto it = x_by_row.find(ae.column);
        if (it == x_by_row.end()) continue;               // no matching rows in X
        const auto& vec = it->second;
        double mul = ae.value;
        for (const auto& xe : vec) {
            size_t row_idx = ae.row * N + xe.column;
            tempY[tid][row_idx] += mul * xe.value;
        }
    }

    // accumulate thread results into the final Y
    for (int t = 0; t < nthreads; ++t) {
        const auto& tY = tempY[t];
        for (size_t idx = 0; idx < M * N; ++idx)
            Y[idx] += tY[idx];
    }
}
