#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Optimised LU factorisation for a sparse matrix A (COO format) into
 * explicit L (lower triangular, unit diagonal) and U (upper triangular)
 * stored in row‑major order.  The algorithm keeps the 𝑂(𝑁²) memory
 * footprint and is parallelised over the outer loop with OpenMP.
 */
void luFactorize(std::vector<COOElement> const& A,
                  std::vector<double> &L,
                  std::vector<double> &U,
                  size_t N)
{
    /* ------------------------------------------------------------------
     *  1. Build a dense matrix from the COO input.  We use a single
     *     contiguous vector to benefit from spatial locality and to
     *     minimise cache misses during the factorisation.
     * ------------------------------------------------------------------ */
    std::vector<double> A_dense(N * N, 0.0);
    for (auto const& e : A)
        A_dense[e.row * N + e.column] = e.value;

    /* ------------------------------------------------------------------
     *  2.  Initialise L and U to zero.  L will automatically get a unit
     *     diagonal later.  The work below is split over the outer loop
     *     (row i), which is independent for each iteration.
     * ------------------------------------------------------------------ */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* ------------------------------------------------------------------
     *  3.  LU factorisation, parallelised over rows (outer loop only).
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(N); ++i) {
        // Compute U[i][j] for j >= i and L[i][j] for j < i
        for (size_t j = 0; j < N; ++j) {
            size_t idx = i * N + j;

            // Upper triangular part (including diagonal)
            if (j >= i) {
                double val = A_dense[idx];
                for (size_t k = 0; k < i; ++k) {
                    val -= L[i * N + k] * U[k * N + j];
                }
                U[idx] = val;
            }

            // Lower triangular part (strictly below diagonal)
            if (i > j) {
                double val = A_dense[idx];
                for (size_t k = 0; k < j; ++k) {
                    val -= L[i * N + k] * U[k * N + j];
                }
                // Avoid division by zero: U[j][j] is non‑zero for a proper LU
                L[idx] = val / U[j * N + j];
            }
        }
        // Unit diagonal for L
        L[i * N + i] = 1.0;
    }
}
