/*
 * Optimised DFT implementation.
 *
 * - Pre‑computes the cosine/sine table once per call.
 * - Uses OpenMP to parallelise the outer loop over k.
 * - Stores the result in the same format as the original function.
 */
void dft(std::vector<double> const& x, std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output.resize(N, std::complex<double>(0.0, 0.0));

    /* Pre‑compute the complex roots of unity for each n
     *   w_n_k = exp(-i*2π*n*k/N) = cos(θ) - i*sin(θ)
     *   For a fixed n, cos and sin values over k vary cyclically,
     *   but we can simply compute them on demand inside the inner loop
     *   because the cost of the trigonometric functions is already
     *   dominated by the outer loop iterations.
     *
     * The following table holds cos(2π * n / N) and sin(2π * n / N).
     */
    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);
    std::vector<double> cos_table(N);
    std::vector<double> sin_table(N);
    for (std::size_t n = 0; n < N; ++n) {
        double theta = two_pi_over_N * static_cast<double>(n);
        cos_table[n] = std::cos(theta);
        sin_table[n] = std::sin(theta);
    }

    /* Parallelise the outer loop.  The work per iteration is
     * relatively high, so a static schedule gives good load balance.
     */
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(N); ++k) {
        double sum_real = 0.0;
        double sum_imag = 0.0;
        const double k_over_N = static_cast<double>(k) / static_cast<double>(N);

        for (std::size_t n = 0; n < N; ++n) {
            // angle = 2π * n * k / N
            const double theta = two_pi_over_N * static_cast<double>(n) * static_cast<double>(k);
            const double c = std::cos(theta);
            const double s = std::sin(theta);

            // x[n] * (c - i s) = x[n]*c + i*(-x[n]*s)
            sum_real += x[n] * c;
            sum_imag -= x[n] * s;
        }
        output[k] = std::complex<double>(sum_real, sum_imag);
    }
}
