 * The image is N×N, stored row‑major. Out‑of‑bounds neighbours are treated
 * as 0. Results are clamped to [0,255].
 */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int>& imageOut,
                           std::size_t N)
{
