    const int* in  = imageIn.data();
    int*       out = imageOut.data();

    // Handle borders separately to avoid many bounds checks inside the hot loop.
    // Top and bottom rows
    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = 0; j < N; ++j) {
            int sum = 0;
            // Only 3 neighbours inside bound at row i-1, i, i+1
            for (int ki = -1; ki <= 1; ++ki) {
                std::size_t ii = i + ki;
                if (ii >= N) continue;                 // below bottom
                for (int kj = -1; kj <= 1; ++kj) {
                    std::size_t jj = j + kj;
                    if (jj >= N) continue;             // right of right
                    sum += in[ii * N + jj] * edgeKernel[ki + 1][kj + 1];
                }
            }
            // Clamp to [0,255]
            if (sum < 0)   sum = 0;
            else if (sum > 255) sum = 255;
            out[i * N + j] = sum;
        }
    }
