    #pragma omp parallel for schedule(static, 1024)
    for (std::size_t ai = 0; ai < lenA; ++ai) {
        const COOElement &a = A_ptr[ai];
        if (a.row < M && a.column < N) {
            double contrib = alpha * a.value * x_ptr[a.column];
