/* Compute one iteration of a 5-point 2D jacobi stencil on `input`.
   Stores the result in `output`.  The arrays are NxN, row‑major.
   This version keeps the exact numerical behaviour while exploiting
   data locality and multi‑threading.  It uses a single flat loop
   with an explicit index so the compiler can better vectorise
   the inner calculations, and OpenMP parallelises the outermost
   dimension. */
void jacobi2D(std::vector<double> const& input,
              std::vector<double> &output,
              std::size_t N)
{
    const double inv5 = 0.2;          // 1/5.0
    const std::size_t step = N;       // stride between rows

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t base = i * step;
        std::size_t base_up   = (i > 0)   ? ((i - 1) * step) : SIZE_T_MAX;
        std::size_t base_down = (i + 1 < N) ? ((i + 1) * step) : SIZE_T_MAX;

        for (std::size_t j = 0; j < N; ++j)
        {
            double sum = input[base + j];
            if (base_up   != SIZE_T_MAX) sum += input[base_up   + j];
            if (base_down != SIZE_T_MAX) sum += input[base_down + j];
            if (j > 0)                     sum += input[base + j - 1];
            if (j + 1 < N)                 sum += input[base + j + 1];
            output[base + j] = sum * inv5;
        }
    }
}
