        #pragma omp for collapse(2) schedule(static)
        for (size_t i = 0; i < n - 2; ++i)
            for (size_t j = i + 1; j < n - 1; ++j)
            {
                const double cross_ij = points[i].x * points[j].y -
                                        points[i].y * points[j].x;
                for (size_t k = j + 1; k < n; ++k)
                {
                    // Compute area using the cross product form:
                    // area = |cross_ij + b×c + c×a| / 2
                    const double area = std::abs(cross_ij
                                 + points[j].x * points[k].y - points[j].y * points[k].x
                                 + points[k].x * points[i].y - points[k].y * points[i].x) * 0.5;
                    if (area < local_min) local_min = area;
                }
            }
        // Reduce to global minimum
        #pragma omp critical
        if (local_min < global_min) global_min = local_min;
    }

    return global_min;
}
