/*
 * Multiply an MxN matrix A by a vector x.
 * A is stored in row‑major order, x has N elements, y must have M elements.
 * The function is fully thread‑safe (no race conditions) and keeps the
 * exact numerical semantics of the reference implementation.
 */
inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>&   y,
                 size_t M, size_t N) noexcept
{
    const double* a = A.data();
    const double* vx = x.data();
    double* vy          = y.data();

    const size_t blockSize = 64;              // rows per thread block
    const size_t unroll    = 4;               // inner loop unroll factor

    #pragma omp parallel for schedule(static, blockSize) collapse(1)
    for (size_t i = 0; i < M; ++i) {
        const double *a_row = a + i * N;
        double sum = 0.0;
        size_t j = 0;
        for (; j + unroll <= N; j += unroll) {
            sum += a_row[j + 0] * vx[j + 0];
            sum += a_row[j + 1] * vx[j + 1];
            sum += a_row[j + 2] * vx[j + 2];
            sum += a_row[j + 3] * vx[j + 3];
        }
        for (; j < N; ++j) sum += a_row[j] * vx[j];
        vy[i] = sum;
    }
}
