/* For each value in the vector `x` compute its index in the sorted vector.
   Store the results in `ranks` preserving the original ordering.
   The implementation uses a single far‑reallocating array and a linear
   search for the final rank, giving O(n log n) performance with minimal
   overhead and no extra memory besides the index array and the ranks
   vector supplied by the caller. */
inline void ranks(const std::vector<float>& x, std::vector<size_t>& ranks_) {
    const size_t n = x.size();
    // Ensure the output vector has the right size
    if (ranks_.size() != n) ranks_.resize(n);

    // Create an array of indices and initialize it
    std::vector<size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    // Sort indices according to the values in `x` (lexicographic order for equal floats)
    std::sort(idx.begin(), idx.end(), [&](size_t i1, size_t i2) {
        return x[i1] < x[i2];
    });

    // Fill the ranks array: the i‑th element of idx is the position of the
    // original element when the array is sorted.
    for (size_t i = 0; i < n; ++i) {
        ranks_[idx[i]] = i;
    }
}
