#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax = b for x.
   A is given in COO format, x and b are dense vectors of length N.
*/
inline size_t idx(size_t row, size_t col, size_t N) noexcept {
    return row * N + col;
}

void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    /* Allocate a flat dense matrix for speed:
       matrix[i*N + j] = A[i][j]   (row-major)                 */
    std::vector<double> mat(N * N, 0.0);
    for (auto const& e : A)
        mat[idx(e.row, e.column, N)] = e.value;

    std::vector<double> rhs = b;          // copy of b
    x.assign(N, 0.0);

    /* Gaussian elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* --------- pivot search (parallel) --------- */
        size_t maxRow = i;
        double maxVal = std::abs(mat[idx(i, i, N)]);
        #pragma omp parallel for reduction(max:maxVal)
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(mat[idx(k, i, N)]);
            #pragma omp critical
            if (val > maxVal) { maxVal = val; maxRow = k; }
        }

        /* --------- swap rows i and maxRow --------- */
        if (maxRow != i) {
            for (size_t j = 0; j < N; ++j) {
                std::swap(mat[idx(maxRow, j, N)], mat[idx(i, j, N)]);
            }
            std::swap(rhs[maxRow], rhs[i]);
        }

        /* --------- eliminate below pivot --------- */
        double pivot = mat[idx(i, i, N)];
        // If pivot is zero, the system is singular – keep behavior the same
        if (pivot == 0.0) continue;

        #pragma omp parallel for
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -mat[idx(k, i, N)] / pivot;
            mat[idx(k, i, N)] = 0.0;                     // explicitly zero
            for (size_t j = i + 1; j < N; ++j) {
                mat[idx(k, j, N)] += factor * mat[idx(i, j, N)];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    /* --------- back substitution --------- */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j) {
            sum -= mat[idx(i, j, N)] * x[j];
        }
        x[i] = sum / mat[idx(i, i, N)];
    }
}
