struct Point {
    double x, y;
};

//--- helper functions ------------------------------------------------------
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x, dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

//--- main routine ----------------------------------------------------------
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(), [](const Point& p1, const Point& p2) {
        return (p1.x < p2.x) || (p1.x == p2.x && p1.y < p2.y);
    });

    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i]);
    }

    // Upper hull
    std::size_t t = hull.size() + 1;
    for (std::size_t i = n; i-- > 1; ) {
        while (hull.size() >= t &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i - 1]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i - 1]);
    }

    hull.pop_back(); // remove duplicate of first point

    // Perimeter
    double perim = 0.0;
    for (std::size_t i = 0; i < hull.size(); ++i)
        perim += dist(hull[i], hull[(i + 1) % hull.size()]);

    return perim;
}
