#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

/* Compute the fourier transform of x. Store the result in output.
   The algorithm is an in‑place, radix‑2 Cooley‑Tukey FFT.
   It produces the same ordering as the original reference implementation. */
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<std::complex<double>>& output)
{
    output = x;
    const std::size_t N = output.size();
    if (N <= 1) return;

    /* ----- Bit‑reverse permutation ----- */
    std::size_t m = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        // reverse bits of j with respect to m bits
        j = ((j & 0xaaaaaaaa) >> 1) | ((j & 0x55555555) << 1);
        j = ((j & 0xcccccccc) >> 2) | ((j & 0x33333333) << 2);
        j = ((j & 0xf0f0f0f0) >> 4) | ((j & 0x0f0f0f0f) << 4);
        j = ((j & 0xff00ff00) >> 8) | ((j & 0x00ff00ff) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - m);
        if (j > i) std::swap(output[i], output[j]);
    }

    /* ----- FFT stages ----- */
    for (std::size_t s = 1; s <= m; ++s) {
        std::size_t m2 = 1U << s;               // stage length
        std::size_t m1 = m2 >> 1;               // half length
        std::complex<double> w_m = std::exp(std::complex<double>(0.0, -M_PI / m1));

        /* loop over sub‑transforms of length m2 */
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m2) {
            std::complex<double> w = 1.0;
            for (std::size_t j = 0; j < m1; ++j) {
                std::complex<double> t = w * output[k + j + m1];
                std::complex<double> u = output[k + j];
                output[k + j] = u + t;
                output[k + j + m1] = u - t;
                w *= w_m;
            }
        }
    }
}
