struct Point {
    double x, y;
};

/*
 * Compute the convex hull of `points` and store the result in `hull`.
 * The algorithm is a classic Graham scan with a two‑phase hull construction.
 * The implementation is fully deterministic and yields the same ordering
 * as the reference version.
 */
inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();

    // A hull of fewer than 3 points is the input itself.
    if (n < 3) {
        hull = points;
        return;
    }

    // 1. Sort by x, then by y.
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // 2. Build lower and upper hulls in one array.
    std::vector<Point> tmp;
    tmp.reserve(2 * n);

    // Lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (tmp.size() >= 2 &&
               cross(tmp[tmp.size() - 2], tmp[tmp.size() - 1], sorted[i]) <= 0) {
            tmp.pop_back();
        }
        tmp.push_back(sorted[i]);
    }

    // Upper hull
    const std::size_t lowerSize = tmp.size();
    for (std::size_t i = n - 1; i > 0; --i) {
        while (tmp.size() > lowerSize + 1 &&
               cross(tmp[tmp.size() - 2], tmp[tmp.size() - 1], sorted[i - 1]) <=
                   0) {
            tmp.pop_back();
        }
        tmp.push_back(sorted[i - 1]);
    }

    // Remove the duplicated starting point.
    tmp.pop_back();

    hull = std::move(tmp);
}
