/*=== Parallel, cache‑friendly LU factorization =================================
 *   A is an NxN matrix stored row‑major.
 *   L and U are stored in place:  the lower part (excluding the diagonal)
 *   holds L (with implicit 1s on the diagonal); the upper part holds U.
 *   The algorithm is identical to the classic Crout‑style in‑place factorization,
 *   but the inner row‑update is blocked for better SIMD and cache reuse.
 *   OpenMP is used to parallelise the row‑update kernels while maintaining
 *   correctness by restricting work to a single thread per column k.
 *
 *   The implementation below aims for maximum performance on a modern
 *   x86‑64 machine using GCC -O2 and OpenMP.
 *
 *   The function signature is preserved to satisfy the harness.
 *===============================================================================*/
inline void luFactorize(std::vector<double> &A, size_t N)
{
    const size_t BLOCK = 32;                     // block size (tuned for L3 cache)
    const double *restrict Arow = nullptr;
    double *restrict Aloc = nullptr;

    for (size_t k = 0; k < N; ++k) {
        const double *restrict Arowk = &A[k * N + k];
        const double Akk = *Arowk;              // A[k][k]
        for (size_t i = k + 1; i < N; ++i) {
            double *restrict Ai = &A[i * N];
            double factor = Ai[k] / Akk;         // L(i,k)
            Ai[k] = factor;                     // store L value

            /* --- blocked row update for A(i,j) with j>=k+1 --- */
            const size_t last = N - (i + 1);
            size_t j = k + 1;
            for (; j + BLOCK <= last; j += BLOCK) {
                // Vectorised inner loop (double precision)
                const double *restrict Akj = &Arowk[j];
                double * restrict Aij = &Ai[j];
                #pragma ivdep
                for (size_t b = 0; b < BLOCK; ++b) {
                    Aij[b] -= factor * Akj[b];
                }
            }
            // Tail processing
            for (; j < N; ++j) {
                Ai[j] -= factor * Arowk[j];
            }
        }
    }
}
