inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if ((N & (N - 1)) != 0) { // N must be power of two
        throw std::runtime_error("fftConjugate: N must be a power of two");
    }

    // ----- Bit‑reversal permutation (single pass) -----
    const std::size_t m = static_cast<std::size_t>(std::log2(N));
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = i;
        rev = ((rev & 0xaaaaaaaa) >> 1) | ((rev & 0x55555555) << 1);
        rev = ((rev & 0xcccccccc) >> 2) | ((rev & 0x33333333) << 2);
        rev = ((rev & 0xf0f0f0f0) >> 4) | ((rev & 0x0f0f0f0f) << 4);
        rev = ((rev & 0xff00ff00) >> 8) | ((rev & 0x00ff00ff) << 8);
        rev = ((rev >> 16) | (rev << 16)) >> (32 - m);
        if (rev > i) {
            std::swap(x[i], x[rev]);
        }
    }

    // ----- Radix‑2 iterative FFT -----
    for (std::size_t s = 1; s <= m; ++s) {
        const std::size_t half = 1ULL << (s - 1);
        const std::size_t full = half << 1;
        const double angle = -M_PI / half;            // -2π / full
        const std::complex<double> w_temp = std::exp(std::complex<double>(0, angle));
        #pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < N; j += full) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t k = 0; k < half; ++k) {
                std::size_t even = j + k;
                std::size_t odd  = even + half;
                const std::complex<double> t = w * x[odd];
                x[odd] = x[even] - t;
                x[even] += t;
                w *= w_temp;
            }
        }
    }

    // ----- Conjugate each coefficient -----
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
