        for (std::size_t i = 0; i < x.size(); ++i) {
            if (x[i] != 0) {
                local.push_back(x[i]);
            }
        }
        // Merge local buffers into the global vector.
        #pragma omp critical
        nonZero.insert(nonZero.end(), local.begin(), local.end());
    }

    if (nonZero.empty()) { // nothing to sort
        return;
    }

    // Sort the non‑zero values.
    std::sort(nonZero.begin(), nonZero.end());

    // Replace the non‑zero elements in the original vector with the sorted values.
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            x[i] = nonZero[idx++];
        }
    }
}
