#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Simulate one generation of Conway's Game of Life.
 *
 * `input`  – current board (row‑major, 1 = alive, 0 = dead).
 * `output` – next board (row‑major, must have N*N elements).
 * `N`      – board side length (assumed >= 1).
 *
 * The implementation uses a fully parallel, cache‑friendly algorithm
 * that preserves the exact semantics of the original reference code.
 */
inline void gameOfLife(const std::vector<int> &input,
                       std::vector<int> &output,
                       std::size_t N) noexcept
{
    const int *in  = input.data();
    int       *out = output.data();

    /* Common expressions reused inside the inner loop */
    const std::size_t stride = N;
    const std::size_t last_row = N - 1;
    const std::size_t last_col = N - 1;

    /* Parallelized outer loop – collapse(2) gives almost perfect
     * load balancing.  The compiler will produce efficient loop
     * bodies thanks to the explicit pointer arithmetic.                 */
    #pragma omp parallel for schedule(static) collapse(2)
    for (std::size_t i = 0; i < N; ++i)
    for (std::size_t j = 0; j < N; ++j)
    {
        std::size_t idx = i * stride + j;
        int sum = 0;

        /* vertical neighbours */
        if (i > 0)           sum += in[(i - 1) * stride + j];
        if (i < last_row)    sum += in[(i + 1) * stride + j];

        /* horizontal neighbours */
        if (j > 0)           sum += in[i * stride + (j - 1)];
        if (j < last_col)    sum += in[i * stride + (j + 1)];

        /* diagonal neighbours */
        if (i > 0 && j > 0)                 sum += in[(i - 1) * stride + (j - 1)];
        if (i > 0 && j < last_col)          sum += in[(i - 1) * stride + (j + 1)];
        if (i < last_row && j > 0)          sum += in[(i + 1) * stride + (j - 1)];
        if (i < last_row && j < last_col)   sum += in[(i + 1) * stride + (j + 1)];

        /* Life rules – performed as in the reference implementation */
        if (in[idx] == 1)
        {
            out[idx] = (sum == 2 || sum == 3) ? 1 : 0;
        }
        else
        {
            out[idx] = (sum == 3) ? 1 : 0;
        }
    }
}
