/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
struct MinDiff {
    double value;
    std::size_t idx;
};

#pragma omp declare reduction(minimum : MinDiff :                                 \
    omp_out = (omp_in.value < omp_out.value) ? omp_in : omp_out)              \
    initializer(omp_priv = {std::numeric_limits<double>::infinity(), 0ULL})

size_t findClosestToPi(const std::vector<double> &x) {
    const std::size_t n = x.size();
    if (n == 0) return 0;            // undefined behaviour for empty vector, but keep consistency

    const double pi = M_PI;

    MinDiff best;
    best.value = std::abs(x[0] - pi);
    best.idx   = 0;

    /* Parallel loop with reduction on the best (difference, index) pair.
     * The loop processes the data in blocks to reduce overhead and
     * benefits from SIMD vectorisation done automatically by the compiler.
     */
#pragma omp parallel for reduction(minimum: best) schedule(static)
    for (std::size_t i = 1; i < n; ++i) {
        const double diff = std::abs(x[i] - pi);
        if (diff < best.value) {
            best.value = diff;
            best.idx   = i;
        }
    }

    return best.idx;
}
