```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Multiply the matrix A by the matrix B. Store the results in the matrix C.
 * A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
 * The matrices are stored in row-major order.
 *
 * Optimised implementation:
 *   • Hierarchical cache blocking (tile sizes 64x64 for L1/L2).
 *   • Parallelised outer loop over rows of A and C with OpenMP.
 *   • Pointer arithmetic to minimise index computations.
 */
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    constexpr size_t BLOCK_M = 64;   // tile size for M dimension
    constexpr size_t BLOCK_K = 64;   // tile size for K dimension
    constexpr size_t BLOCK_N = 64;   // tile size for N dimension

    // Parallelise the outermost M loop; each thread works on disjoint i‑tiles.
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK_M) {
        size_t i_max = std::min(ii + BLOCK_M, M);
        for (size_t kk = 0; kk < K; kk += BLOCK_K) {
            size_t k_max = std::min(kk + BLOCK_K, K);
            for (size_t jj = 0; jj < N; jj += BLOCK_N) {
                size_t j_max = std::min(jj + BLOCK_N, N);

                // Pointers to the current tiles
                const double *A_blk = A.data() + ii * K + kk;
                const double *B_blk = B.data() + kk * N + jj;
                double       *C_blk = C.data() + ii * N + jj;

                size_t K_block = k_max - kk;
                size_t N_block = j_max - jj;

                for (size_t i = 0; i < (i_max - ii); ++i) {
                    const double *A_row = A_blk + i * K;
                    double       *C_row = C_blk + i * N;
                    for (size_t k = 0; k < K_block; ++k) {
                        double a_val = A_row[k];
                        const double *B_row = B_blk + k * N;
                        // Unroll the inner j loop modestly
                        size_t j = 0;
                        for (; j + 3 < N_block; j += 4) {
                            C_row[j]   += a_val * B_row[j];
                            C_row[j+1] += a_val * B_row[j+1];
                            C_row[j+2] += a_val * B_row[j+2];
                            C_row[j+3] += a_val * B_row[j+3];
                        }
                        for (; j < N_block; ++j) {
                            C_row[j] += a_val * B_row[j];
                        }
                    }
                }
            }
        }
    }
}
