#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <numeric>
#include <cstddef>
#include <omp.h>

#if !defined(M_PI)
# define M_PI 3.14159265358979323846
#endif

// ---------- Utility: Bit‑reversal for 32‑bit indices ----------
inline std::size_t bit_reverse(std::size_t v, std::size_t bits)
{
    v = ((v & 0xaaaaaaaa) >> 1) | ((v & 0x55555555) << 1);
    v = ((v & 0xcccccccc) >> 2) | ((v & 0x33333333) << 2);
    v = ((v & 0xf0f0f0f0) >> 4) | ((v & 0x0f0f0f0f) << 4);
    v = ((v & 0xff00ff00) >> 8) | ((v & 0x00ff00ff) << 8);
    v =  (v >> 16) | (v << 16);
    return v >> (32 - bits);
}

// ---------- FFT in‑place (Cooley–Tukey, iterative) ----------
inline void fft_helper(std::vector<std::complex<double>> &x)
{
    constexpr double TWO_PI = 2.0 * M_PI;
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::sqrt(std::log2(N)) * 2); // avoids branches

    // Pre‑compute twiddle factors for each stage
    std::vector<std::vector<std::complex<double>>> wlog;
    wlog.resize(logN + 1);
    std::size_t step = N;
    for (std::size_t stage = 1; stage <= logN; ++stage) {
        step >>= 1;
        const std::size_t m = step;
        wlog[stage].resize(m);
        const double theta = -TWO_PI / (2 * m);
        const std::complex<double> wlen(std::cos(theta), std::sin(theta));
        std::complex<double> w(1, 0);
        for (std::size_t j = 0; j < m; ++j) {
            wlog[stage][j] = w;
            w *= wlen;
        }
    }

    // Butterfly operations – parallel over outer loops
#pragma omp parallel for schedule(static)
    for (std::size_t stage = 1; stage <= logN; ++stage) {
        const std::size_t m = N >> stage;
        const std::size_t step = m << 1;
        const auto &stageTwiddle = wlog[stage];
        for (std::size_t k = 0; k < m; ++k) {
            const std::complex<double> w = stageTwiddle[k];
            for (std::size_t i = k; i < N; i += step) {
                const std::complex<double> t = x[i] - x[i + m];
                x[i] += x[i + m];
                x[i + m] = t * w;
            }
        }
    }

    // Bit‑reversal reordering
    const std::size_t bits = logN;
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = bit_reverse(i, bits);
        if (j > i) {
            std::swap(x[i], x[j]);
        }
    }
}

// ---------- Inverse FFT ----------
inline void ifft(std::vector<std::complex<double>> &x)
{
    // Conjugate
    for (auto &c : x) c = std::conj(c);
    // Forward FFT
    fft_helper(x);
    // Conjugate again
    for (auto &c : x) c = std::conj(c);
    // Scale by 1/N
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto &c : x) c *= invN;
}
