// Finds the index of the first even number in the input vector.
// If none exists, returns x.size().
//
// The implementation uses a tight pointer loop with a small
// compile‑time unroll to minimize branch mispredictions.  It is
// intentionally written to be fast on modern x86‑64 CPUs while
// preserving the exact semantics of the original code.
size_t findFirstEven(const std::vector<int>& x) noexcept {
    const std::size_t n = x.size();
    if (n == 0)
        return 0;

    const int* ptr = x.data();            // fast access to underlying array
    std::size_t i = 0;

    // Unroll by 8 to reduce loop overhead and improve instruction
    // level parallelism without changing behavior.
    const std::size_t unroll = 8;
    const std::size_t limit = n & ~(unroll - 1); // largest multiple of 8 <= n

    for (; i < limit; i += unroll) {
        if (ptr[i] % 2 == 0)   return i;
        if (ptr[i + 1] % 2 == 0) return i + 1;
        if (ptr[i + 2] % 2 == 0) return i + 2;
        if (ptr[i + 3] % 2 == 0) return i + 3;
        if (ptr[i + 4] % 2 == 0) return i + 4;
        if (ptr[i + 5] % 2 == 0) return i + 5;
        if (ptr[i + 6] % 2 == 0) return i + 6;
        if (ptr[i + 7] % 2 == 0) return i + 7;
    }

    // Finish with any remaining elements
    for (; i < n; ++i) {
        if (ptr[i] % 2 == 0)
            return i;
    }
    return n;
}
