/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither. */
inline bool xorContains(const std::vector<int> &x,
                        const std::vector<int> &y,
                        int val) noexcept
{
    bool foundInX = false, foundInY = false;

    /* Scan x for the value first – can stop immediately once found. */
    for (int v : x)
    {
        if (v == val)
        {
            foundInX = true;
            break;
        }
    }

    /* Scan y for the value – stop once found. */
    for (int v : y)
    {
        if (v == val)
        {
            foundInY = true;
            break;
        }
    }

    /* XOR of the two boolean results. */
    return foundInX != foundInY;
}
