13_geometry_closest_pair_2d:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

/*------------------------------------------------------------------------
 *  Fast closest‑pair in 2‑D
 *  ---------------------------------------------------------------
 *  Implements the classic O(n log n) Divide‑&‑Conquer algorithm.
 *  Parallelism is inserted on the top‑level recursion (split into
 *  two halves) using OpenMP.  After the recursive calls the two
 *  halves are merged into a single sorted-by‑y array, and the strip
 *  candidate search is performed in a single thread because it is
 *  already very fast for the typical workloads.
 *  The algorithm keeps the original behaviour (exact distances)
 *  but replaces the quadratic dbl‑loop.
 *---------------------------------------------------------------------*/
namespace detail {

inline double dist(const Point &a, const Point &b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx*dx + dy*dy);
}

/* Recursively find closest pair distance.
 * points     : sorted by x
 * aux        : auxiliary array of same size, used for merging by y
 * l, r       : interval [l, r) in points
 * returns     : minimal distance in the interval
 */
double closestRec(const std::vector<Point> &points,
                  std::vector<Point> &aux,
                  size_t l, size_t r) {
    size_t n = r - l;
    if (n <= 3) {                     // brute‑force for few points
        double d = std::numeric_limits<double>::max();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j) {
                double d2 = dist(points[i], points[j]);
                if (d2 < d) d = d2;
            }
        /* sort by y for merging */
        std::sort(points.begin() + l, points.begin() + r,
                  [](const Point &a, const Point &b){ return a.y < b.y; });
        return d;
    }

    size_t mid = l + n/2;
    double midx = points[mid].x;

    /* ----------------------------------------------------------------
     *  Parallel divide step: run two halves concurrently if there are
     *  enough threads left.  A static threshold (e.g. > 1e4 points)
     *  prevents oversubscription for tiny sub‑problems.
     *  ----------------------------------------------------------------
     */
    double d_left, d_right;
    #pragma omp task shared(points,aux) if(n > 5000 && omp_get_max_threads() > 1)
    d_left = closestRec(points, aux, l, mid);
    #pragma omp task shared(points,aux) if(n > 5000 && omp_get_max_threads() > 1)
    d_right = closestRec(points, aux, mid, r);
    #pragma omp taskwait
    double d = std::min(d_left, d_right);

    /* Merge sorted halves by y into aux */
    size_t i = l, j = mid, k = l;
    while (i < mid && j < r) {
        if (points[i].y < points[j].y) aux[k++] = points[i++];
        else aux[k++] = points[j++];
    }
    while (i < mid) aux[k++] = points[i++];
    while (j < r) aux[k++] = points[j++];
    for (size_t t = l; t < r; ++t) points[t] = aux[t];

    /* Build strip of points within d of the division line */
    std::vector<Point> strip;
    strip.reserve(n);
    for (size_t i = l; i < r; ++i) {
        if (std::fabs(points[i].x - midx) < d)
            strip.push_back(points[i]);
    }

    /* Check at most 7 neighbours for each point in the strip */
    for (size_t i = 0; i < strip.size(); ++i)
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < d; ++j) {
            double d2 = dist(strip[i], strip[j]);
            if (d2 < d) d = d2;
        }

    return d;
}

} // namespace detail

/*--------------------------------------------------------------------
 *  User facing entry point – same signature as the original function.
 *--------------------------------------------------------------------*/
double closestPair(std::vector<Point> const& points) {
    if (points.size() < 2) return 0.0;

    // Work on a copy to keep input untouched
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> aux(pts.size());

    double result;

    #pragma omp parallel
    {
        #pragma omp single
        result = detail::closestRec(pts, aux, 0, pts.size());
    }
    return result;
}
