#pragma once
#include <vector>
#include <omp.h>

/* Solve the linear system Ax = b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   The function keeps the exact behaviour of the original version.
*/
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Copy A and b so that the input vectors remain unchanged
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    // --- Gaussian elimination with partial pivoting omitted for speed ---
    for (size_t i = 0; i + 1 < N; ++i)
    {
        double pivot = A_copy[i * N + i];
        if (pivot == 0.0) return;           // singular – keep original behaviour

        double inv_pivot = 1.0 / pivot;

        // Parallelise the elimination of rows below the pivot row
        #pragma omp parallel for schedule(static, 64) num_threads(8)
        for (size_t j = i + 1; j < N; ++j)
        {
            double factor = A_copy[j * N + i] * inv_pivot;

            // Update the j‑th row
            // The inner loop is sequential as it writes to distinct
            // memory locations for the same j.
            size_t k = i;
            for (; k + 7 < N; k += 8) {
                A_copy[j * N + k]     -= factor * A_copy[i * N + k];
                A_copy[j * N + k + 1] -= factor * A_copy[i * N + k + 1];
                A_copy[j * N + k + 2] -= factor * A_copy[i * N + k + 2];
                A_copy[j * N + k + 3] -= factor * A_copy[i * N + k + 3];
                A_copy[j * N + k + 4] -= factor * A_copy[i * N + k + 4];
                A_copy[j * N + k + 5] -= factor * A_copy[i * N + k + 5];
                A_copy[j * N + k + 6] -= factor * A_copy[i * N + k + 6];
                A_copy[j * N + k + 7] -= factor * A_copy[i * N + k + 7];
            }
            for (; k < N; ++k) {
                A_copy[j * N + k] -= factor * A_copy[i * N + k];
            }

            // Update the right‑hand side
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // --- Back substitution (fully sequential, N <= typical problem size) ---
    for (long i = static_cast<long>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        size_t j = i + 1;
        for (; j + 7 < N; j += 8) {
            sum += A_copy[i * N + j]   * x[j];
            sum += A_copy[i * N + (j+1)] * x[j+1];
            sum += A_copy[i * N + (j+2)] * x[j+2];
            sum += A_copy[i * N + (j+3)] * x[j+3];
            sum += A_copy[i * N + (j+4)] * x[j+4];
            sum += A_copy[i * N + (j+5)] * x[j+5];
            sum += A_copy[i * N + (j+6)] * x[j+6];
            sum += A_copy[i * N + (j+7)] * x[j+7];
        }
        for (; j < N; ++j) {
            sum += A_copy[i * N + j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
